export const UrlMetadataSchema = {
  type: 'object',
  description: 'Context of the a single url retrieval.',
  properties: {
    retrievedUrl: { type: 'string', description: 'Retrieved url by the tool.' },
    urlRetrievalStatus: {
      type: 'string',
      description: 'Status of the url retrieval.',
      enum: [
        'URL_RETRIEVAL_STATUS_UNSPECIFIED',
        'URL_RETRIEVAL_STATUS_SUCCESS',
        'URL_RETRIEVAL_STATUS_ERROR',
        'URL_RETRIEVAL_STATUS_PAYWALL',
        'URL_RETRIEVAL_STATUS_UNSAFE',
      ],
    },
  },
} as const

export const UsageMetadataSchema = {
  type: 'object',
  description: "Metadata on the generation request's token usage.",
  properties: {
    promptTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Number of tokens in the prompt. When `cached_content` is set, this is still the total effective prompt size meaning this includes the number of tokens in the cached content.',
    },
    cachedContentTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Number of tokens in the cached part of the prompt (the cached content)',
    },
    candidatesTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Total number of tokens across all the generated response candidates.',
    },
    toolUsePromptTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Output only. Number of tokens present in tool-use prompt(s).',
    },
    thoughtsTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Output only. Number of tokens of thoughts for thinking models.',
    },
    totalTokenCount: {
      type: 'integer',
      format: 'int32',
      description:
        'Total token count for the generation request (prompt + thoughts + response candidates).',
    },
    promptTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities that were processed in the request input.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    cacheTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities of the cached content in the request input.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    candidatesTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities that were returned in the response.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    toolUsePromptTokensDetails: {
      type: 'array',
      description:
        'Output only. List of modalities that were processed for tool-use request inputs.',
      items: { $ref: '#/$defs/ModalityTokenCount' },
    },
    serviceTier: {
      type: 'string',
      description: 'Output only. Service tier of the request.',
      enum: ['unspecified', 'standard', 'flex', 'priority'],
    },
  },
  $defs: {
    ModalityTokenCount: {
      type: 'object',
      description: 'Represents token counting info for a single modality.',
      properties: {
        modality: {
          type: 'string',
          description: 'The modality associated with this token count.',
          enum: [
            'MODALITY_UNSPECIFIED',
            'TEXT',
            'IMAGE',
            'VIDEO',
            'AUDIO',
            'DOCUMENT',
          ],
        },
        tokenCount: {
          type: 'integer',
          format: 'int32',
          description: 'Number of tokens.',
        },
      },
    },
  },
} as const

export const VideoMetadataSchema = {
  type: 'object',
  description:
    'Deprecated: Use `GenerateContentRequest.processing_options` instead. Metadata describes the input video content.',
  properties: {
    startOffset: {
      type: 'string',
      format: 'google-duration',
      description: 'Optional. The start offset of the video.',
    },
    endOffset: {
      type: 'string',
      format: 'google-duration',
      description: 'Optional. The end offset of the video.',
    },
    fps: {
      type: 'number',
      format: 'double',
      description:
        'Optional. The frame rate of the video sent to the model. If not specified, the default value will be 1.0. The fps range is (0.0, 24.0].',
    },
  },
} as const

export const VoiceConfigSchema = {
  type: 'object',
  description: 'The configuration for the voice to use.',
  properties: { prebuiltVoiceConfig: { $ref: '#/$defs/PrebuiltVoiceConfig' } },
  $defs: {
    PrebuiltVoiceConfig: {
      type: 'object',
      description: 'The configuration for the prebuilt speaker to use.',
      properties: {
        voiceName: {
          type: 'string',
          description: 'The name of the preset voice to use.',
        },
      },
    },
  },
} as const

export const WebSchema = {
  type: 'object',
  description: 'Chunk from the web.',
  properties: {
    uri: {
      type: 'string',
      description: 'Output only. URI reference of the chunk.',
    },
    title: { type: 'string', description: 'Output only. Title of the chunk.' },
  },
} as const

export const WebSearchSchema = {
  type: 'object',
  description: 'Standard web search for grounding and related configurations.',
  properties: {},
} as const
